sql:
SELECT MAX(expenditure_amount) AS max_expenditure_amount
FROM budget_expenditures
WHERE fiscal_year_id = (SELECT fiscal_year_id FROM fiscal_years WHERE year = 2023);

SELECT MAX(start_date) AS latest_start_date
FROM budget_activities
WHERE agency_id = (SELECT agency_id FROM agencies WHERE agency_name = 'Department of Revenue');

SELECT MAX(current_balance) AS max_balance
FROM budget_balances
WHERE activity_id = 0 AND fiscal_year_id = 1;

SELECT COUNT(*) 
FROM budget_requests 
WHERE approval_status = 'approved';

SELECT activity_name
FROM budget_activities
WHERE status = 'active';

external_knowledge:
- Fiscal years typically span 12 consecutive months and are used for budgeting, financial reporting, and financial planning; 
- A budget activity can be any event or program that requires financial resources; 
- Expenditure refers to the amount spent for a budget activity;
- Change amount represents the difference in expenditure or allocation from one fiscal year to the next;
- Access logs are records of who accessed the budget activity data and when;
- Cumulative totals are calculated by adding up the totals for each fiscal year.

sql:
SELECT SUM(requested_amount) AS total_requested
FROM budget_requests
WHERE fiscal_year_id = 1;

SELECT fiscal_year_id, SUM(expenditure_amount) AS total_expenditures
FROM budget_expenditures
GROUP BY fiscal_year_id;

SELECT expenditure_amount, approval_status
FROM budget_expenditures
WHERE approval_status = 'pending';

SELECT COUNT(*) AS active_activities_count
FROM budget_activities
WHERE status = 'active';

SELECT COUNT(*) AS total_expenditures
FROM budget_expenditures
WHERE fiscal_year_id = 1;

SELECT fiscal_year_id, SUM(enacted_budget) AS total_enacted_budget
FROM budget_data
GROUP BY fiscal_year_id;

SELECT enacted_budget, percent_change
FROM budget_data
WHERE fiscal_year_id IN (SELECT fiscal_year_id FROM fiscal_years WHERE status = 'closed');

SELECT approval_status
FROM budget_requests
WHERE fiscal_year_id = 1;
